import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import AnimatedNumber from '../../components/AnimatedNumber';

const COLORS = ['#1a56db','#10b981','#f59e0b','#ef4444','#6366f1','#06b6d4','#ec4899','#8b5cf6'];
const roleBadge = { admin:'badge-red', hod:'badge-yellow', faculty:'badge-purple', student:'badge-blue' };
const STATUS_BADGE = { submitted:'badge-yellow', approved:'badge-green', rejected:'badge-red' };

function DetailModal({ title, icon, onClose, children, count }) {
  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 720 }}>
        <div className="modal-header">
          <span className="modal-title">{icon} {title}</span>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div style={{ maxHeight:'65vh', overflowY:'auto' }}>
          {children}
        </div>
        <div style={{ padding:'12px 20px', borderTop:'1px solid var(--border)', fontSize:13, color:'var(--text-muted)', background:'#f8fafc' }}>
          Total: <strong>{count}</strong> record{count !== 1 ? 's' : ''}
        </div>
      </div>
    </div>
  );
}

export default function AdminDashboard() {
  const [data,    setData]    = useState(null);
  const [loading, setLoading] = useState(true);
  const [modal,   setModal]   = useState(null);
  const [modalData, setModalData]   = useState([]);
  const [loadingModal, setLoadingModal] = useState(false);
  const [fSearch, setFSearch] = useState('');
  const [fSem,    setFSem]    = useState('');
  const [fRole,   setFRole]   = useState('');
  const [fDept,   setFDept]   = useState('');
  const [filtered, setFiltered] = useState([]);

  const SEMESTERS = [1,2,3,4,5,6,7,8];

  useEffect(() => {
    axios.get('/api/admin/stats')
      .then(res => { setData(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  // Apply filters
  React.useEffect(() => {
    let result = [...modalData];
    if (fSearch) { const q = fSearch.toLowerCase(); result = result.filter(r => r.name?.toLowerCase().includes(q) || r.rollNumber?.toLowerCase().includes(q) || r.student?.name?.toLowerCase().includes(q) || r.code?.toLowerCase().includes(q)); }
    if (fSem)  result = result.filter(r => r.semester === Number(fSem));
    if (fRole) result = result.filter(r => r.role === fRole);
    if (fDept) result = result.filter(r => r.department?._id === fDept || r.department?.name === fDept);
    setFiltered(result);
  }, [modalData, fSearch, fSem, fRole, fDept]);

  const openModal = async (type, title, icon) => {
    setFSearch(''); setFSem(''); setFRole(''); setFDept('');
    setModal({ type, title, icon });
    setModalData([]);
    setLoadingModal(true);
    try {
      if (type === 'students') {
        const res = await axios.get('/api/admin/users', { params: { role: 'student' } });
        setModalData(res.data.users.filter(u => u.isActive));
      } else if (type === 'faculty') {
        const res = await axios.get('/api/admin/users', { params: { role: 'faculty' } });
        setModalData(res.data.users.filter(u => u.isActive));
      } else if (type === 'hods') {
        const res = await axios.get('/api/admin/users', { params: { role: 'hod' } });
        setModalData(res.data.users.filter(u => u.isActive));
      } else if (type === 'depts') {
        const res = await axios.get('/api/admin/departments');
        setModalData(res.data.departments.filter(d => d.isActive));
      } else if (type === 'subjects') {
        const res = await axios.get('/api/admin/subjects');
        setModalData(res.data.subjects || []);
      } else if (type === 'marks') {
        const res = await axios.get('/api/admin/marks');
        setModalData(res.data.marks || []);
      }
    } catch { setModalData([]); }
    finally { setLoadingModal(false); }
  };

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
  if (!data)   return <div className="empty-state"><div className="empty-icon">⚠️</div><div className="empty-text">Failed to load</div></div>;

  const { stats, studentsByDept, studentsBySem } = data;
  const semData  = studentsBySem.map(s => ({ name: `Sem ${s._id}`, students: s.count }));
  const deptData = studentsByDept.map(d => ({ name: d.deptName || 'Unknown', value: d.count }));

  const statCards = [
    { key:'students', value:stats.totalStudents,     label:'Total Students',   icon:'👨‍🎓', color:'blue',   title:'All Students'      },
    { key:'faculty',  value:stats.totalFaculty,      label:'Faculty Members',  icon:'👩‍🏫', color:'green',  title:'All Faculty'       },
    { key:'hods',     value:stats.totalHods,         label:'HODs',             icon:'🧑‍💼', color:'purple', title:'All HODs'          },
    { key:'depts',    value:stats.totalDepartments,  label:'Departments',      icon:'🏢',  color:'yellow', title:'All Departments'   },
    { key:'subjects', value:stats.totalSubjects,     label:'Subjects',         icon:'📚', color:'cyan',   title:'All Subjects'      },
    { key:'marks',    value:stats.totalMarksEntries, label:'Marks Entries',    icon:'📊', color:'red',    title:'All Marks Entries' },
  ];

  const renderContent = () => {
    if (loadingModal) return (
      <div className="empty-state" style={{ padding:48 }}>
        <div className="spinner" style={{ margin:'0 auto' }}></div>
      </div>
    );
    const displayData = filtered.length > 0 || (fSearch||fSem||fRole||fDept) ? filtered : modalData;
    if (!displayData.length) return (
      <div className="empty-state">
        <div className="empty-icon">📭</div>
        <div className="empty-text">No records found</div>
      </div>
    );

    if (['students','faculty','hods'].includes(modal.type)) return (
      <table>
        <thead>
          <tr>
            <th>#</th><th>Name</th><th>Roll Number</th><th>Role</th><th>Department</th>
            {modal.type === 'students' && <><th>Sem</th><th>Section</th></>}
          </tr>
        </thead>
        <tbody>
          {displayData.map((u,i) => (
            <tr key={u._id}>
              <td>{i+1}</td>
              <td className="fw-600">{u.name}</td>
              <td style={{ fontFamily:'monospace', fontSize:12 }}>{u.rollNumber}</td>
              <td><span className={`badge ${roleBadge[u.role]||'badge-gray'}`}>{u.role}</span></td>
              <td>{u.department?.name || '—'}</td>
              {modal.type === 'students' && (
                <>
                  <td><span className="badge badge-blue">Sem {u.semester}</span></td>
                  <td>{u.section || '—'}</td>
                </>
              )}
            </tr>
          ))}
        </tbody>
      </table>
    );

    if (modal.type === 'depts') return (
      <table>
        <thead><tr><th>#</th><th>Department Name</th><th>Code</th><th>Description</th><th>Status</th></tr></thead>
        <tbody>
          {displayData.map((d,i) => (
            <tr key={d._id}>
              <td>{i+1}</td>
              <td className="fw-600">{d.name}</td>
              <td><span className="badge badge-blue">{d.code}</span></td>
              <td className="text-muted">{d.description || '—'}</td>
              <td><span className={`badge ${d.isActive?'badge-green':'badge-red'}`}>{d.isActive?'Active':'Inactive'}</span></td>
            </tr>
          ))}
        </tbody>
      </table>
    );

    if (modal.type === 'subjects') return (
      <table>
        <thead><tr><th>#</th><th>Subject Name</th><th>Code</th><th>Department</th><th>Semester</th><th>Credits</th><th>Max Marks</th></tr></thead>
        <tbody>
          {displayData.map((s,i) => (
            <tr key={s._id}>
              <td>{i+1}</td>
              <td className="fw-600">{s.name}</td>
              <td><span className="badge badge-purple">{s.code}</span></td>
              <td>{s.department?.name || '—'}</td>
              <td>Sem {s.semester}</td>
              <td>{s.credits}</td>
              <td>{s.maxMidMarks}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );

    if (modal.type === 'marks') return (
      <table>
        <thead><tr><th>#</th><th>Student</th><th>Roll No</th><th>Subject</th><th>Exam</th><th>Marks</th><th>Faculty</th><th>Status</th></tr></thead>
        <tbody>
          {displayData.map((m,i) => (
            <tr key={m._id}>
              <td>{i+1}</td>
              <td className="fw-600">{m.student?.name}</td>
              <td style={{ fontFamily:'monospace', fontSize:12 }}>{m.student?.rollNumber}</td>
              <td>{m.subject?.name} <span style={{ fontSize:11, color:'var(--text-muted)' }}>({m.subject?.code})</span></td>
              <td><span className="badge badge-blue">{m.midExam}</span></td>
              <td className="fw-600">{m.totalMarks}/30</td>
              <td className="text-muted">{m.faculty?.name}</td>
              <td>
                <span className={`badge ${STATUS_BADGE[m.status]||'badge-gray'}`}>{m.status}</span>
                {m.isLocked && <span className="badge badge-red" style={{ marginLeft:4 }}>🔒</span>}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  return (
    <div>
      <div className="stats-grid">
        {statCards.map((card, idx) => (
          <div key={card.key}
            className={`stat-card ${card.color} stat-card-animated`}
            onClick={() => openModal(card.key, card.title, card.icon)}
            style={{ '--delay':`${idx * 0.08}s`, cursor:'pointer', userSelect:'none' }}
            title={`Click to view ${card.title}`}
          >
            <div className="stat-icon">{card.icon}</div>
            <div>
              <div className="stat-value"><AnimatedNumber value={card.value} /></div>
              <div className="stat-label">{card.label}</div>
              <div style={{ fontSize:10, color:'var(--primary)', marginTop:2, fontWeight:600 }}>Click to view →</div>
            </div>
          </div>
        ))}
      </div>

      {/* Charts */}
      <div className="charts-grid">
        <div className="card">
          <div className="card-header"><span className="card-title">📊 Students by Semester</span></div>
          <div className="card-body">
            {semData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={semData} margin={{ top:5, right:10, left:-10, bottom:5 }}>
                    <XAxis dataKey="name" tick={{ fontSize:11 }} />
                    <YAxis allowDecimals={false} tick={{ fontSize:11 }} />
                    <Tooltip />
                    <Bar dataKey="students" fill="#1a56db" radius={[4,4,0,0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No student data</div></div>}
          </div>
        </div>

        <div className="card">
          <div className="card-header"><span className="card-title">🏢 Students by Department</span></div>
          <div className="card-body">
            {deptData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart margin={{ top:5, right:5, left:5, bottom:5 }}>
                    <Pie data={deptData} cx="50%" cy="45%" outerRadius="60%"
                      dataKey="value" label={({ value }) => value} labelLine>
                      {deptData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                    </Pie>
                    <Tooltip />
                    <Legend layout="horizontal" verticalAlign="bottom" align="center" wrapperStyle={{ fontSize:11, paddingTop:8 }} />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No department data</div></div>}
          </div>
        </div>
      </div>

      {/* Detail Modal */}
      {modal && (
        <DetailModal
          title={modal.title}
          icon={modal.icon}
          onClose={() => { setModal(null); setModalData([]); }}
          count={modalData.length}
        >
          {renderContent()}
        </DetailModal>
      )}
    </div>
  );
}
